-- ---- Stub: lurek.tween.update --------------------------------------------
--@api-stub: lurek.tween.update
-- Call this every frame from lurek.process(dt) -- without it no tween or
-- spring value will ever change no matter how many animations you started.
local demo_dt = 1 / 60
lurek.tween.update(demo_dt)
print("tween pool ticked, active:", lurek.tween.getActiveCount())

-- ---- Stub: lurek.tween.tween ---------------------------------------------
--@api-stub: lurek.tween.tween
-- Animate any numeric field on a Lua table smoothly to a target value.
-- Returns a Tween handle you can pause, repeat, or monitor for completion.
local player = { x = 0.0, y = 200.0, alpha = 1.0 }
local move_tween = lurek.tween.tween(player, { x = 640.0 }, 1.2, "easeOutCubic")
print("player.x will reach 640 in 1.2 s")

-- ---- Stub: lurek.tween.sequence ------------------------------------------
--@api-stub: lurek.tween.sequence
-- Chain animations so each step starts only after the previous one finishes --
-- ideal for cutscenes, dialog reveals, or multi-phase enemy entrances.
local enemy = { x = -80.0, y = 300.0, alpha = 0.0 }
local seq = lurek.tween.sequence()
seq:tween(enemy, { alpha = 1.0 }, 0.3, "linear")
seq:tween(enemy, { x = 200.0 }, 0.8, "easeOutBack")
seq:callback(function() print("enemy reached position") end)
seq:start()

-- ---- Stub: lurek.tween.parallel ------------------------------------------
--@api-stub: lurek.tween.parallel
-- Run multiple tweens simultaneously and get one handle for the whole group --
-- useful when you animate position + alpha + scale at the same time.
local panel = { x = 0.0, y = -100.0, alpha = 0.0 }
local par = lurek.tween.parallel()
par:tween(panel, { y = 0.0 }, 0.5, "easeOutQuad")
par:tween(panel, { alpha = 1.0 }, 0.5, "linear")
par:start()

-- ---- Stub: lurek.tween.delay ---------------------------------------------
--@api-stub: lurek.tween.delay
-- Fire a callback after a fixed delay without managing a manual timer --
-- or use delay() as a named pause step inside a TweenSequence.
local respawn_timer = lurek.tween.delay(3.0, function()
    print("3 s elapsed -- enemy respawned")
end)
print("respawn delay registered:", respawn_timer)

