-- ---- Stub: lurek.tween.getActiveCount ------------------------------------
--@api-stub: lurek.tween.getActiveCount
-- Use as a cheap per-frame diagnostic gauge to confirm animations drain
-- correctly and are not leaking across scene transitions.
local budget = 64
