end

-- ---- Stub: lurek.tween.registerEasing ------------------------------------
--@api-stub: lurek.tween.registerEasing
-- Register a custom curve so you can reference it by name in any tween call --
-- keeps animation code readable instead of embedding inline math functions.
lurek.tween.registerEasing("punchIn", function(t)
    -- sharp overshoot ease-in curve
    return t * t * ((2.70158 + 1) * t - 2.70158)
end)
print("custom 'punchIn' easing registered")

