-- ---- Stub: lurek.tween.spring --------------------------------------------
--@api-stub: lurek.tween.spring
-- A spring converges to its target with natural overshoot and settling --
-- ideal for camera follow, cursor lag, or any "heavy object" motion feel.
local cam = { x = 0.0, y = 0.0 }
local spring = lurek.tween.spring(cam, { x = 320.0, y = 240.0 }, { stiffness = 80, damping = 12 })
print("camera spring started; cam will overshoot then settle at (320, 240)")

