-- ---- Stub: Spring:update -------------------------------------------------
--@api-stub: Spring:update
-- Tick the spring forward in your process loop -- it writes new values into
-- the target table and returns false once the spring has fully settled.
local still_moving = spring:update(0.016)
if not still_moving then
    print("spring settled at", cam.x, cam.y)
end

-- ---- Stub: Spring:isSettled ----------------------------------------------
--@api-stub: Spring:isSettled
-- Settled means all axes are within a tiny threshold of the target --
-- poll this to trigger a landing sound or snap to the exact pixel position.
if spring:isSettled() then
    cam.x = math.floor(cam.x + 0.5)  -- snap to nearest pixel
    cam.y = math.floor(cam.y + 0.5)
    print("camera snapped to exact target")
end

-- ---- Stub: Spring:isActive -----------------------------------------------
--@api-stub: Spring:isActive
-- A cancelled spring is immediately inactive; a settled spring stays active
-- until explicitly cancelled.  Skip update() calls once the spring is done.
if spring:isActive() then
    spring:update(0.016)
else
    print("spring finished -- no need to tick it further")
end

-- ---- Stub: Spring:setTarget ----------------------------------------------
--@api-stub: Spring:setTarget
-- Redirect the spring mid-flight -- it smoothly steers toward the new target
-- while preserving current velocity so the motion stays continuous.
spring:setTarget({ x = 500.0, y = 300.0 })
print("camera spring redirected to (500, 300)")

-- ---- Stub: Spring:setStiffness -------------------------------------------
--@api-stub: Spring:setStiffness
-- Higher stiffness means faster response with more overshoot; lower values
-- give a heavy, sluggish feel.  Typical range: 20 (floaty) to 200 (snappy).
spring:setStiffness(120)
print("spring stiffness raised to 120 -- snappier camera response")

-- ---- Stub: Spring:setDamping ---------------------------------------------
--@api-stub: Spring:setDamping
-- Low damping = bouncy overshoot; high = overdamped with no oscillation.
-- Rule of thumb: critical damping is roughly 2 * sqrt(stiffness).
spring:setDamping(20)
print("spring damping lowered -- camera will bounce slightly on target changes")

