print("move tween resumed from", player.x)

-- ---- Stub: Tween:isActive ------------------------------------------------
--@api-stub: Tween:isActive
-- Gate follow-up actions on isActive so they only fire after the animation
-- fully completes rather than requiring a manual completion flag.
if move_tween:isActive() then
    print("player still moving, progress:", move_tween:getProgress())
else
    print("player arrived at x =", player.x)
end

-- ---- Stub: Tween:getProgress ---------------------------------------------
--@api-stub: Tween:getProgress
-- Raw 0..1 progress ignores easing and yoyo -- use it to drive a loading bar
-- that advances linearly while the animated property uses a curved easing.
local pct = move_tween:getProgress() * 100
print(string.format("player move: %.0f%% through its duration", pct))

-- ---- Stub: Tween:setRepeat -----------------------------------------------
--@api-stub: Tween:setRepeat
-- 0 = play once (default).  -1 = loop forever.  N = N extra cycles.
-- Combine with setYoyo(true) for a seamless ping-pong loop.
local pulse = lurek.tween.tween(player, { alpha = 0.2 }, 0.5, "easeInOutSine")
pulse:setRepeat(-1)  -- loop forever
pulse:setYoyo(true)  -- 1.0 -> 0.2 -> 1.0 -> ...
print("infinite pulse alpha tween started")

-- ---- Stub: Tween:setYoyo -------------------------------------------------
--@api-stub: Tween:setYoyo
-- Yoyo plays forward then backward each cycle, making looped animations
-- like hovering NPCs or breathing lights look seamless without a jump cut.
local hover = lurek.tween.tween(player, { y = player.y - 12 }, 0.7, "easeInOutSine")
hover:setRepeat(-1)
hover:setYoyo(true)
print("hover tween running: player bobs 12 px up and down")

